void heap_overflow(int n) {
    char *buf = (char *)malloc(10);
    if (buf == NULL) return;
    for (int i = 0; i <= n; i++) {
        buf[i] = 'A';
    }
    free(buf);
}

void run_command(const char *user_input) {
    char cmd[256];
    sprintf(cmd, "ls %s", user_input);
    system(cmd);
}

void safe_alloc(int n) {
    if (n <= 0 || n > 1024) return;
    char *buf = (char *)malloc(n);
    if (buf == NULL) return;
    for (int i = 0; i < n; i++) {
        buf[i] = 'A';
    }
    buf[n - 1] = '\0';
    free(buf);
}
